var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"열흘 전","JPN":"10日前","ENG":"Ten days earlier","TWN":"十天前"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 재건 도시 <color=#ffd34c>ARC-NL1</color>\\n구 네덜란드, 암스테르담","JPN":"管理局再建都市<color=#ffd34c>ARC-NL1</color>\\n旧オランダ、アムステルダム","ENG":"Administration Rebuilt City <color=#ffd34c>ARC-NL1</color>\\nAmsterdam, Old Netherlands","TWN":"管理局重建城市<color=#ffd34c>ARC-NL1</color>\\n舊荷蘭 阿姆斯特丹"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"subtitle","speaker":null,"text":{"KOREA":"다국적 합자 대침식 연구소 – 퓨처 앳 워\\n<color=#ffd34c>제3지부 항공 우주 연구소</color>","JPN":"多国籍合資対侵食戦研究所 - フューチャーアットウォー\\n<color=#ffd34c>第3支部航空宇宙研究所</color>","ENG":"Multinational Joint Anti-Corruption Research - Future-at-War\\n<color=#ffd34c>3rd Branch, Aerospace Research Lab</color>","TWN":"跨國合資反侵蝕研究所-天啟兵器\\n<color=#ffd34c>第三分部航空航太研究所</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"그래서……?","JPN":"で……？","ENG":"So...?","TWN":"所以……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"샤레이드 한복판에서 벡터 변환 중이던 망원 렌즈를 저격으로 멈추게 했다는 거야?","JPN":"シャレードの真ん中でベクター変換中だった望遠レンズを狙撃で止めたっていうの？","ENG":"Are you saying you managed to stop the Zoom Lens mid-vector conversion with a sniper shot right in the middle of Charade?","TWN":"你是說在查雷德中心，靠狙擊成功阻止了望遠鏡頭的向量轉換？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"뭐, 결과적으로는 그렇게 됐단다.","JPN":"まあ、結果的にそうなったわね。","ENG":"Well, that's what happened, in the end.","TWN":"嗯，事情就是這樣發生的。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"너, 지금 제 정신이야? 잘못해서 망원 렌즈에 맞았으면, 어쩔 뻔했어?","JPN":"あんた、気は確か？　間違って望遠レンズに当たったらどうするつもりだったの？","ENG":"Are you out of your mind? What if you had missed and hit the Zoom Lens?","TWN":"你瘋了嗎？如果你射偏了打到望遠鏡頭怎麼辦？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"만약 그랬으면, 샤레이드 한 구역이 지도에서 사라져 버렸을지도 모른다고!","JPN":"シャレードのど真ん中にでっかい穴ができたかもしれないのよ！","ENG":"If that had happened, an entire section of Charade could have been wiped off the map!","TWN":"如果那樣，整個查雷德的區域可能會被徹底剷平！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"내가 말했잖아! 민간 피해는 최소화하라고 말이야!","JPN":"言ったでしょ！　民間の被害は最小限にしろって！","ENG":"Didn't I tell you? Keep civilian casualties to a minimum!","TWN":"我不是告訴過你了嗎？務必將平民傷亡降到最低！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"후후, 이거 이상하구나.","JPN":"ふふ、おかしいわねえ。","ENG":"Fu fu. That's strange.","TWN":"呵呵，真奇怪。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"쥐새끼는 소리에 민감하다던데, 왜 우리 쥐새끼는 말귀를 잘 못 알아들을까?","JPN":"ネズミは音に敏感だって言うけど、どうしてこっちのネズミは音に鈍感なのかしら。","ENG":"They say rats are sensitive to sound, so why is our little rat so bad at understanding words?","TWN":"老鼠對聲音很敏感，為什麼我們的老鼠卻這麼不聽話呢？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"뭐라고?","JPN":"はあ？","ENG":"What did you say?","TWN":"你說什麼？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"나야말로 말했잖니? 망원 렌즈가 아니라, 그걸 들고 있던 꼬맹이를 노린 거라고.","JPN":"私こそ言ったはずよ。望遠レンズではなく、それを持っていたチビちゃんを狙ったって。","ENG":"I told you, didn't I? I wasn't aiming for the Zoom Lens. I was aiming for the kid holding it.","TWN":"我不是告訴你了嗎？我沒瞄準望遠鏡頭，是瞄準拿著它的小鬼。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그것도 일부러 크게 다치지 않게끔, 탄도를 계산해서 빗맞힌 거란다.","JPN":"しかもわざと大怪我しないように、弾道を計算して外したのよ。","ENG":"And I made sure to miss intentionally, calculating the trajectory so she wouldn't get seriously injured.","TWN":"而且我特意計算了軌跡故意射偏，避免她受傷。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그게 아니면, 지금 내가 가꾼 장미들의 실력을 의심하는 거니?","JPN":"それとも、私が育てたバラたちの腕を疑っているのかしら？","ENG":"Unless, of course, you're questioning the skill of the roses I've cultivated.","TWN":"當然，除非你質疑我培育的玫瑰的技術。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"네가 가꾼 장미? 허! 아주 웃기고 자빠졌네……!","JPN":"あんたが育てたバラ？　は！　笑わせないで……！","ENG":"The roses you cultivated? Ha! That's ridiculous...!","TWN":"你培育的玫瑰？哈！荒謬……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"역시 범죄자는 사고방식이 다른 가봐? 양심이 있다면 말은 똑바로 하는 게 어때?","JPN":"さすがに犯罪者は考え方が普通と違うみたいね？　良心ってものがあるなら正直に言ったらどう？","ENG":"Guess criminals really do think differently. If you had any conscience, you'd speak more honestly.","TWN":"看來罪犯果然思維不同。如果你有點良心，說話會誠實一點。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"그건 알파트릭스의 유산을 멋대로 훔쳐다 쓰고 있을 뿐이잖아?","JPN":"アルファトリックスの遺産を勝手に盗んで使っているだけだって。","ENG":"You're just stealing Alphatrix's legacy and using it for your own purposes.","TWN":"你不過是在偷用阿爾法崔克斯的遺產，拿來為自己謀利。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"자기 성과도 아닌 걸, 부풀려서 말하면 부끄럽지도 않아?","JPN":"自分の成果でもないのに、そんなことを言って恥ずかしくないの？","ENG":"Aren't you ashamed to claim something that's not even your own work?","TWN":"不是自己的成績，卻誇大其詞地說出來，不覺得羞愧嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"그것도 그런 말도 안 되는 미친 기술을……!","JPN":"しかも、あんなマッドサイエンス……！","ENG":"Especially when it's some insane technology like that...!","TWN":"尤其這還是什麼瘋狂科技……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"후후, 구 관리국의 공학자 출신이라고 해도, 역시 자기 분야가 아니면 문외한인가 보네.","JPN":"ふふ、旧管理局の工学者出身とはいっても、専門分野以外は何もわかっていないみたいね。","ENG":"Fu fu. Even if you were a former engineer of the Old Administration, I guess you're clueless when it's not your field.","TWN":"呵呵。即使你曾是舊管理局的工程師，別的領域你還真是一竅不通。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그 도박꾼이 남긴 클론은 엄연한 실패작이었단다.","JPN":"あのギャンブラーが残したクローンは失敗作だったわ。","ENG":"The clones left behind by that degenerate were nothing but failures.","TWN":"那個墮落者留下的克隆人不過是失敗品。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"꽃의 품종이 뛰어날 뿐, 그 꽃을 가꿀 주인이 엉망이었으니까 말이지.","JPN":"優れていたのは花の品種だけで、その花を育てる主がクズなんだもの。","ENG":"The flowers were splendid, but the gardener was a mess.","TWN":"花朵再美，園丁卻一團糟。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"아무리 색과 향이 화려하다고 하더라도, 일찍 시들어 버린다면 가치가 없는 법이지.","JPN":"いくら色と香りが華麗だとしても、すぐに枯れてしまっては価値なんてない。","ENG":"No matter how vibrant the colors or how fragrant the scent, a flower that wilts too soon is worthless.","TWN":"不管顏色多鮮豔，香味多芬芳，枯萎太早的花就是沒價值。"},"stage":{"bg":"ALPHA_05","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"갬블러는 그깟 복수에 미쳐 자기가 가진 꽃을 가꾸는 데 소홀했지만, 나는 다르거든.","JPN":"ギャンブラーは復讐に夢中で、自分の花の世話を疎かにしたけれど、私は違う。","ENG":"Gambler was too obsessed with revenge to properly tend to the flowers he had. But I'm different.","TWN":"賭徒太迷戀復仇，無法好好照顧他培育的花。但我不同。"},"stage":{"bg":"ALPHA_05","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"맨션은 대를 거쳐서 오랫동안 존재해 왔고, 나는 한평생을 정원의 주인으로 살아왔단다.","JPN":"マンションは古くから代を重ねて存在してきたし、私は一生を庭の主として生きてきた。","ENG":"The Mansion has existed for generations, and I have spent my entire life as the master of the garden.","TWN":"曼森已經存在了許多年，而我我一生都作為花園的主人生活著。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"싹을 알아보고, 꽃을 피우는 법, 꽃이 오랫동안 시들지 않도록 가꾸는 법…….","JPN":"芽を見分け花を咲かせる方法、花が長い時間枯れないように世話をする方法……","ENG":"I know how to spot a sprout, how to make it bloom, and how to keep it from withering too soon...","TWN":"我知道如何辨認幼芽，如何讓它盛開，如何避免它早早凋零…"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그리고 설령, 시들어 버릴지라도 그 가치를 잃지 않게 만드는 법을 알고 있지.","JPN":"たとえ枯れてしまっても、その価値を失わなずに済む方法を知っているわ。","ENG":"And even if it does wither, I know how to ensure it never loses its value.","TWN":"即使凋零，我也知道怎麼確保它永不失去價值。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그러니까 저 애들은 나를 만나, 비로소 꽃이 될 수 있는 거란다.","JPN":"だからあの子たちは私に出会って、やっと花になれるの。","ENG":"So those children could only truly become flowers after meeting me.","TWN":"因此，那些孩子只有遇到我後才能真正成為花朵。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그리고 프로젝트 오즈를 통해, 임상 테스트를 마친 사고 공유 시스템…….","JPN":"そしてプロジェクト・オズを経て、臨床テストを終えた思考共有システム……","ENG":"And with the clinical testing of the thought-sharing system completed through Project OZ...","TWN":"在經過奧茲國計畫完成的思維共享系統臨床測試後…"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"<color=#ffd34c>하우스홀드</color> 네트워크는 저 아이들을 점점 더 완벽에 가까운 꽃으로 성장시켜 줄 테지.","JPN":"<color=#ffd34c>ハウスホールド</color>ネットワークはあの子たちをますます完璧に近い花に成長させてくれるはずよ。","ENG":"The <color=#ffd34c>Household</color> Network will continue to nurture them into more perfect flowers.","TWN":"<color=#ffd34c>家用</color>網路將繼續培育她們成為更完美的花朵。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"결국에는 나를 떠나버린 그 아이보다도 훨씬 더 아름답게 피어날 거야.","JPN":"そして、私から離れていったあの子よりもずっと美しく咲くの。","ENG":"Eventually, they will bloom far more beautifully than that kid who left me.","TWN":"終有一天，她們會盛開得比離開我的那個孩子更美麗。"},"stage":{"bg":"SS_MAID_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"물론, 아직은 이제 막 떡잎을 틔웠을 뿐이지만.","JPN":"もちろん、まだやっと芽が生えただけだけど。","ENG":"Of course, right now, they're still just budding.","TWN":"當然，現在她們仍只是含苞待放。"},"stage":{"bg":"SS_MAID_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"하우스홀드 네트워크…….","JPN":"ハウスホールドネットワーク……","ENG":"Household Network...","TWN":"家用網路…"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"인간의 의식을 하나의 네트워크로 연결해서 생각을 공유하는 집단 사고 시스템…….","JPN":"人間の意識を1つのネットワークで繋げて、考えを共有する集団思考システム……","ENG":"A collective thought-sharing system that links human consciousness into a single network...","TWN":"一個將人類意識聯結成單一網路的集體思維共享系統…"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"흥, 참 대단들 하시네.","JPN":"ふん、まったく恐れ入るわ。","ENG":"Hmph, that's really something.","TWN":"哼，真厲害。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"평의회는 어떻게 이런 비인도적인 기술을 손에 넣었을까?","JPN":"評議会はどうやってこんな非人道的な技術を手に入れたのかしら。","ENG":"How did the Council get their hands on such inhumane technology?","TWN":"評議會怎麼會取得這種非人道的技術？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"기술의 발전은 그만한 대가를 치러야 할 텐데?","JPN":"技術の発展はそれ相応の代償を払わなければならないはずよ。","ENG":"Advancements in technology usually come with a price.","TWN":"技術進步往往伴隨代價。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"설령 대가를 치르더라도 결국 기술은 발전하기 마련이란다.","JPN":"たとえ代償を払うことになるとしても、技術は発展するもの。","ENG":"Even if we must pay a price, technology will continue to evolve.","TWN":"即使必須付出代價，技術仍會持續進化。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"쓸데없는 도덕과 관습에 묶여, 남들보다 뒤처질 바엔, 할 수 있는 걸 하는 편이 낫지.","JPN":"つまらない道徳と慣習に捉われて出遅れるよりは、私にできることをしたまでよ。","ENG":"Better to do what you can than to cling to pointless morals and conventions and fall behind.","TWN":"做你能做的，總比固守毫無意義的道德和慣例、被落在後面來得好。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"관리 실패 이후 줄곧 쥐구멍에 틀어박혀 있던 어느 쥐새끼랑은 다르게 말이야.","JPN":"管理失敗以後、ずっと狭い穴に閉じこもっていたネズミとは違ってね。","ENG":"Unlike a certain rat who's been hiding in a hole ever since the Administration Failure.","TWN":"不像某隻自管理局失敗後就藏在洞裡的老鼠。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"뭐? 너, 지금 말 다했어?","JPN":"何ですって？　けんか売ってるの？","ENG":"What? Are you done talking?","TWN":"什麼？你說完了嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"글쎄? 애초에 나는 쥐새끼, 네가 뭘 그리 깨끗한 척 구는지 도통 이해가 안 되거든.","JPN":"さあね。そもそも私はね、ネズミ。あなたが綺麗事を言っているのが理解できないの。","ENG":"Who knows? I just don't get why a rat like you is acting so holier-than-thou.","TWN":"誰知道？我就是不懂為什麼她這種老鼠裝得這麼道貌岸然。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"구 관리국에서 클론 병사를 찍어내던 건, 세계를 지키기 위한 어쩔 수 없는 선택이었고.","JPN":"旧管理局でクローン兵士を作ったのは、世界を守るために仕方のない選択で。","ENG":"The Old Administration manufactured clone soldiers as an unavoidable choice to protect the world.","TWN":"舊管理局製造克隆士兵是保護世界的無奈之舉。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"검은 평의회의 정원에서 장미를 가꾸는 건, 비인도적인 일이라고 주장할 셈이니?","JPN":"黒い評議会の庭でバラたちを育てるのは、非人道的なことだとでも主張するつもり？","ENG":"Are you saying that tending to roses in the Dark Council's garden is any less humane?","TWN":"你是說照顧黑暗評議會花園的玫瑰就不人道？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그 구성원들이 단지 범죄자들이니까? 하! 그거 참으로 편리한 논리로구나?","JPN":"その構成員が犯罪者だから？　は！　まったく便利な論理ね。","ENG":"Just because the members are criminals? Ha! How convenient.","TWN":"只是因為成員是罪犯？哈！說得真輕鬆。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그럼, 애초부터 그 대단하신 구 관리국의 영웅분들께서 세계를 지켜냈다면 좋았을 것을.","JPN":"だったら最初からそのお偉い旧管理局の英雄たちが世界を守っていればよかったのよ。","ENG":"If those great heroes of the Old Administration had managed to protect the world in the first place, we wouldn't be in this mess.","TWN":"如果舊管理局那些大英雄一開始能守護世界，我們就不會落得這種局面。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그래서? 누구 때문에 세계가 이 꼴이 됐는데, 그 패배자들은 어디 처박혀 있는 거니?","JPN":"それで？　誰かさんのせいで世界がこの様なのに、その負け犬どもはどこに隠れてるのかしらね？","ENG":"So, tell me. Who's responsible for this world being in such a state, and where are those so-called heroes hiding now?","TWN":"那告訴我，這世界變成這樣是誰的責任，那些所謂英雄現在藏哪裡？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"입 닥쳐, 맨션 마스터.","JPN":"黙れ、マンションマスター。","ENG":"Shut up, Mansion Master.","TWN":"閉嘴，曼森主人。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"내 앞에서 그들의 삶을 모욕하지 마. 죽여버린다.","JPN":"私の前で彼らの人生を侮辱しないで。殺すわよ？","ENG":"Don't you dare insult their lives in front of me. I'll kill you.","TWN":"別在我面前羞辱他們，我會殺了你。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"후후, 정원을 파먹는 시궁쥐 주제에 성격조차 고약하구나.","JPN":"ふふ、庭を荒らすドブネズミは性格もひどいわね。","ENG":"Fu fu. The rat that gnaws at the roots of the garden sure has a nasty temper.","TWN":"呵呵，啃食花園根部的老鼠脾氣真差。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"뭐래. 네 향수 냄새가 훨씬 지독하거든?","JPN":"何言ってるの？　あんたの香水の臭いの方がよっぽどひどいわ。","ENG":"Says you. Your stinking perfume is worse.","TWN":"你說誰呢？你那臭香水更糟。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_QM","text":{"KOREA":"두 사람, 이쯤에서 그만두는 게 어떻겠나?","JPN":"2人とも、その辺にしたらどうかね？","ENG":"Why not stop there, both of you?","TWN":"別再吵了，你們兩個。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_QM","text":{"KOREA":"자네들은 서로 입장이 다르지. 어차피 언쟁을 계속해 봤자, 서로 감정만 상하게 될 뿐이라네.","JPN":"君たちは立場が違うんだ。言い争っても、お互い傷つくだけさ。","ENG":"You two come from different perspectives. Continuing this argument will only hurt your feelings.","TWN":"你們來自不同立場，繼續爭吵只會傷感情。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"시끄러워, 깡통. 넌 지금 몇 신 줄 알아?","JPN":"うるさい、ボロ缶。今何時だと思ってるの？","ENG":"Shut up, Tin Can. Do you even know what time it is right now?","TWN":"閉嘴，鐵罐。你知道現在幾點了嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"기계 주제에 시간 감각이 없는 것 같은데, 그 잘난 머리통에 시계라도 박아줄까?","JPN":"機械のくせに時間の感覚がないみたいだけど、その偉そうな頭に時計でも埋め込んであげようか？","ENG":"For a machine, your sense of time seems pretty messed up. Want me to implant a clock in that fancy head of yours?","TWN":"身為機械，你的時間觀念還真糟糕。要我給你裝個時鐘嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"후후, 선물이라면 감사히 받겠네만, 가급적이면 손목 시계로 부탁하지, 닥터.","JPN":"ふふ。プレゼントならありがたくいただくが、なるべく腕時計で頼むよ、ドクター。","ENG":"Haha. If it's a gift, I'll gladly accept it, but I'd prefer a wristwatch, Doctor.","TWN":"哈哈。如果是禮物，我樂意接受，不過我比較想要手錶，博士。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"그리고 오랜만이네, 마담. 내가 보낸 선물은 마음에 들었나?","JPN":"久しぶりだね、マダム。私からのプレゼントは気に入ってくれたかな？","ENG":"It's been a while, Madam. Did you like the gift I sent you?","TWN":"好久不見，夫人。你喜歡我送的禮物嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"하여간 일을 벌여 놓고 마지막에 등장하는 건 여전하구나, 애늙은이.","JPN":"事を始めておいて最後に登場するところは相変わらずね、ませガキさん。","ENG":"As usual, you show up at the end after stirring things up, you old soul.","TWN":"跟平常一樣，你總是在攪局後出現，少年老成。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"뭐, 첫 실전치고는 제법 나쁘지 않았단다. 꽤나 우수한 품종의 꽃이더군.","JPN":"まあ、初実戦にしては悪くなかったわ。なかなか優秀な品種の花のようね。","ENG":"Still, it wasn't bad for a first field test. Quite a remarkable breed of flowers you brought.","TWN":"不過這次第一次實地測試還不錯。你帶來的花朵真是了不起。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"앞으로 어떻게 가꾸느냐에 따라, 우리의 전력이 될 수도 있겠지.","JPN":"この先の育て方次第では、私たちの戦力になるかもしれないわ。","ENG":"Depending on how they're nurtured, they could become our valuable asset.","TWN":"視培育方式，她們可能成為我們珍貴的資產。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"마담의 마음에 들었다니, 그거 다행이군.","JPN":"マダムに気に入ってもらえたようで、何よりだ。","ENG":"I'm glad they caught your interest.","TWN":"很高興她們引起你的興趣。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그래서 그 카나리아 스쿼드는 왜 데리고 오라고 한 거니?","JPN":"それで？　あのカナリア・スクワッドを連れて来いと言ったのはなぜ？","ENG":"So why did you bring the Canary Squad here?","TWN":"那你為什麼帶金絲雀小隊來？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"리그 우승으로 제법 유명해졌지만… 그래봤자 카운터가 아닌 평범한 인간…….","JPN":"リーグ優勝で有名にはなったけど……所詮はカウンターでもないただの人間……","ENG":"They became somewhat famous after winning the league... But they're just ordinary humans, not Counters...","TWN":"她們贏得聯賽後有點名氣……但只是普通人類，不是制裁者……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"이 판에 끼어들 만큼, 중요한 존재는 아니라고 생각하는데?","JPN":"今回のことに途中参加させるほど重要な存在ではないと思うけど？","ENG":"I don't see why they'd be important enough to get involved in this mess.","TWN":"我看不出她們有多重要到會被捲進這種麻煩。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"평범한 인간이라…….","JPN":"ただの人間、か……","ENG":"Ordinary humans...","TWN":"普通人類……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"물론, 천재가 세계를 바꿀 수 있다는 건 관리국의 중요 지침 중 하나라네.","JPN":"もちろん、天才が世界を変えられるというのは管理局の重要指針の一つだ。","ENG":"Of course, one of the core principles of the Administration is that geniuses can change the world.","TWN":"當然，管理局的一個核心原則是天才能改變世界。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"그리고 자네들은 각자의 분야에서 천재성을 드러낸 이들.","JPN":"そして、君たちは各々の分野で天才的な才能を見せていた。","ENG":"You all have shown genius in your respective fields.","TWN":"你們各自在所屬領域都有天賦。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"자네들을 평의회라는 이름으로 한자리에 모은 건, 나름의 이유와 역할이 있기 때문이지.","JPN":"君たちを評議会という名で集めたのは、それなりの理由と役割があるからだ。","ENG":"Bringing you together under the Council's name wasn't without reason or purpose.","TWN":"評議會名義下召集你們並非無的放矢。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"하지만 때때로 평범한 이들에게도 중요한 역할이 주어지기 마련이야.","JPN":"だが、時にはただの人間にも重要な役割が与えられることがある。","ENG":"But sometimes, even ordinary people play crucial roles.","TWN":"但有時候，普通人也扮演關鍵角色。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"결국, 이 세계는 정밀하게 동작하는 기계와 같고…….","JPN":"結局、この世界は精密に動く機械も同然で……","ENG":"In the end, this world functions like a precise machine, and...","TWN":"最終，這個世界運作如同精密機械，"},"stage":{"bg":"MS_1004","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"우리 모두는 그 기계를 구성하는 부품이라고 할 수 있으니까.","JPN":"私たちはみんな、その機械を構成する部品とも言えるんだ。","ENG":"One could say that we are all just parts that make up that machine.","TWN":"我們不過是組成那機械的零件。"},"stage":{"bg":"MS_1005","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_BONE_CRACK_02"},{"id":"L14_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"따라서 쓸모없는 부품이라는 건 존재하지 않아.","JPN":"だから、必要のない部品など存在しない。","ENG":"Therefore, there is no such thing as a useless part.","TWN":"所以沒有多餘的零件。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"또 시작이로구나, 애늙은이.","JPN":"また始まったわね、ませガキさん。","ENG":"There you go again, you old soul.","TWN":"你又來了，少年老成。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"빙빙 돌려서 말할 필요 없단다. 어차피 미쳐버린 네 사상 따위는 전혀 관심 없으니까.","JPN":"遠回しに言う必要はないわ。どうせ狂ったあなたの思想なんて、まったく興味ないもの。","ENG":"There's no need for all this roundabout talk. I'm not interested in your crazy philosophy.","TWN":"別繞圈子了，我對你那瘋狂哲學沒興趣。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그래서 카나리아 스쿼드, 그 애송이들이 무슨 역할을 맡게 된다는 걸까?","JPN":"それで？　カナリア・スクワッド、あのチビちゃんたちはどんな役割を担当することになるのかしら？","ENG":"So, what role are those Canary Squad brats supposed to play?","TWN":"那金絲雀小隊這些孩子該扮演什麼角色？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"그들의 이름 그대로라네, 마담.","JPN":"彼らの名前どおりだよ、マダム。","ENG":"Exactly as their name suggests, Madam.","TWN":"正如她們名字所示，夫人。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"이름 그대로라고?","JPN":"名前どおり？","ENG":"As their name suggests?","TWN":"名字所示？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"탄광 속의 카나리아…….","JPN":"炭鉱の中のカナリア……","ENG":"The canary in the coal mine...","TWN":"煤礦中的金絲雀……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"그 새는 예민한 호흡기를 타고났기에, 탄광에서 광부들의 안전을 예측하는 도구로 쓰였지.","JPN":"その鳥は呼吸器がとても敏感で、炭鉱で鉱員たちの安全を予測する道具として使われた。","ENG":"Because of their sensitive respiratory systems, canaries were used by miners to detect danger.","TWN":"因為呼吸系統敏感，礦工用金絲雀偵測危險。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"그것과 마찬가지로 그들을 세계의 분기점 속에 밀어 넣고, 시험해 볼 생각이야.","JPN":"それと同じく、彼らを世界の分岐点に突き落とし、試してみるつもりだ。","ENG":"Similarly, I plan to place them within the turning point of the world to test a new possibility.","TWN":"類似地，我打算讓她們置身於世界的轉折點，測試新的可能性。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"이 세계에 새롭게 탄생한 가능성을 말이지.","JPN":"この世界に新しく誕生した可能性を。","ENG":"A new possibility that has arisen within this world.","TWN":"一種在這世界出現的新可能性。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"흐음, 또 그때처럼 내가 이해할 수 없는 짓을 꾸미려는 모양이구나.","JPN":"ふーん、またあの時みたいに私には理解できないことを企んでいるようね。","ENG":"Hmm, once again, you're planning something I can't quite comprehend.","TWN":"嗯，你又在策劃我搞不懂的東西了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"뭐, 그딴 건 아무래도 좋아. 보수는 충분하겠지?","JPN":"まあ、そんなことはどうでもいいわ。報酬は十分あるんでしょうね？","ENG":"Well, whatever. As long as the payment is sufficient.","TWN":"無所謂，只要報酬夠多。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"후후, 물론이네.","JPN":"ふふ、もちろんだ。","ENG":"Haha. Of course.","TWN":"哈哈，當然。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"그럼, 모쪼록 두 사람의 협조를 부탁한다네. 마담, 그리고 닥터.","JPN":"では、くれぐれもお互いの協力をお願いするよ。マダム、そしてドクター。","ENG":"Then I'll be counting on your cooperation, Madam, and Doctor.","TWN":"那麼，夫人和博士，就拜託你們合作了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"카나리아의 작은 날개짓이 종국에는 분기점까지 다다를 수 있도록.","JPN":"カナリアの小さな羽ばたきが、終局には分岐点までたどり着けるように。","ENG":"Let's see if the small flutter of the canaries' wings can reach the turning point.","TWN":"看看金絲雀振翅的小小撲動能否抵達轉折點。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"부디, 자네들의 힘과 지혜를 빌려주길 바라네.","JPN":"どうか、君たちの知恵と力を貸してくれたまえ。","ENG":"I hope you lend your strength and wisdom to make it happen.","TWN":"希望你們能以力量和智慧促成這一切。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"……크윽. 여긴 어디지?","JPN":"……くうっ、ここはどこだ？","ENG":"...Kgh. Where am I?","TWN":"……。我在哪裡？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L48_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"메이드 녀석들에게 두들겨 맞은 것 까진 기억나는데… 그 뒤로는……","JPN":"メイドのやつらに殴られたのは覚えてるけど……その後は……","ENG":"I remember getting beaten up by those maids... But after that...","TWN":"記得被那些女僕打過……之後……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"얌마, 꼬맹이. 지금 자고 있을 때가 아니야.","JPN":"おい、おこちゃま。寝てる場合じゃないぞ。","ENG":"Hey, kid. Now's not the time to be sleeping.","TWN":"嘿，孩子。現在不是睡覺的時候。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L1_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"눈 좀 떠 봐. 우리 납치됐다고!","JPN":"目を開けろ。私たち、拉致された！","ENG":"Wake up. We've been kidnapped!","TWN":"醒醒。我們被綁架了！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"으음… 라이카? 여긴 어디예요……?","JPN":"うーん……ライカ？　ここは……？","ENG":"Mm... Laika? Where are we...?","TWN":"嗯……卡？我們在哪裡……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L3_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야, 내가 그걸 어떻게 알겠냐?","JPN":"知るわけないだろ？","ENG":"How would I know?","TWN":"我怎麼知道？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"맨션은 어디까지나 청부 조직일 뿐이야. 아마도 그 뒷배는 따로 있겠지.","JPN":"マンションはあくまでも依頼を遂行するだけ。たぶんバックに別の誰かがいるはずだ。","ENG":"The Mansion is just a contract syndicate. They probably have some backer pulling the strings.","TWN":"曼森不過是個契約組織。他們背後可能有黑手。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"우리가 엿 먹였던 플라티나? 날 쫓고 있던 북방합의체? 그것도 아니라면…….","JPN":"私たちが一発食らわしたプラチナ？　私を追っていた北方合意体？　それとも……","ENG":"Was it Platina, the ones we pissed off? Or the Northern Union who was hunting me down? Or...","TWN":"是我們惹怒的白金那群人？還是追殺我的北方和議會？還是…"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"젠장, 의심 가는 녀석들이 너무 많잖아?","JPN":"くそ、怪しい奴が多すぎる。","ENG":"Damn it. There are too many suspects.","TWN":"該死。嫌疑犯太多了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"에휴, 라이카는 대체 어떤 인생을 살아왔길래, 이렇게 적이 많아요?","JPN":"はあ。いったいどんな人生を生きてきたらこんなに敵が多くなるの？","ENG":"Geez, Laika. What kind of life did you live to have this many enemies?","TWN":"真是的，萊卡。你過去到底幹過什麼事，有這麼多敵人？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카 때문에 제 인생까지 이게 뭐예요?","JPN":"ライカのせいで私の人生までこの様じゃない。","ENG":"Thanks to you, my life's a mess now too, you know.","TWN":"多虧你，我的人生現在也一團糟了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"사돈 남 말하고 앉았네. 피차 샤레이드 하수구에서 만난 사이인데 그딴 게 뭐가 중요해?","JPN":"あんたが言うな。お互いシャレードの下水道で出会った仲じゃないか。","ENG":"Oh, shut it. We both met in the sewers of Charade, so what's the difference?","TWN":"我們兩個半斤八兩吧。我們都是在查雷德下水道裡遇到的，有什麼差別？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"맞아, 내가 구해준 건 잊지 않았겠지? 이번 건은 대충 쌤쌤으로 퉁치자고.","JPN":"そうだ、助けてやったこと、忘れてないよね？　今回のはおあいこってことで。","ENG":"And don't forget I saved you back there. Let's just call it even for now.","TWN":"別忘了我還救過你。現在算扯平了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"쌤쌤은 무슨, 라이카는 꼭 불리하면 그 말 꺼내잖아요.","JPN":"おあいこって。ライカは自分が不利になるといつもその話するくせに。","ENG":"Call it even? Laika, you always pull that line whenever things get tough.","TWN":"扯平？萊卡，你一遇到不利情況就會說這句話。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그러고 보니… 그 마스터라는 사람은 누구예요? 아는 사이 같던데……?","JPN":"そういえば……あのマスターって人は誰なの？　知り合いみたいだったけど……？","ENG":"Come to think of it... Who was that Master person? You seemed to know her...","TWN":"說起來……個主人是誰？你好像認識她……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야씨! 아는 사이는 개뿔! 그 망할 할망구 따위 내가 알 게 뭐야?","JPN":"ちょ！　知り合いなんてとんでもない！　あんなクソババァ、知らないよ！","ENG":"Hey! Seriously?! Why would I know that crazy old hag?","TWN":"嘿！認識個鬼！我怎麼會認識那個瘋婆子？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"할망구……?","JPN":"ババァ……？","ENG":"Old hag...?","TWN":"瘋婆子……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"말씀드렸을 텐데요?","JPN":"言ったはずです。","ENG":"Did I not tell you?","TWN":"我不是告訴你了嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"마스터에 대한 험담은 금기사항이라고 말이죠.","JPN":"マスターの悪口はメイドとして許しがたい禁忌事項ですと。","ENG":"Talking badly about Master is strictly forbidden...","TWN":"不可以對主人不敬…"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"헛!? 어느 틈에……!?","JPN":"はっ！？　いつの間に……！？","ENG":"Huh?! When did she get here...?!","TWN":"蛤！什麼時候來的！？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"깜짝이야! 어이, 깜빡이 좀 켜고 들어오지?","JPN":"びっくりした！　おい、ウィンカーくらいは出せよ。","ENG":"Whoa! At least turn on your blinker before sneaking up on people!","TWN":"哇！偷襲人家之前至少打個方向燈啊？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"깜빡이를 켜다? 그건 어떤 명령이죠?","JPN":"ウィンカーを出す？　それはどういう命令なのでしょうか。","ENG":"Turn on the blinker? What kind of command is that?","TWN":"打方向燈？那是什麼指令？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"뭐……?","JPN":"は……？","ENG":"What...?","TWN":"什麼…"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"어두우니 조명을 밝혀달라는 뜻인가요? 하지만 조명은 이미 켜져 있습니다만.","JPN":"ウィンクをしてほしいという意味でしょうか？　ですが、ここでウィンクなどをしても何の意味もありません。","ENG":"Are you asking me to turn on the lights because it's dark? But the lights are already on.","TWN":"你是說因為天黑所以要我開燈？燈不是已經開了嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"그게 아니라면…….","JPN":"それとも……","ENG":"Or...","TWN":"或者…"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"어, 그러니까…….","JPN":"えっと……だから……","ENG":"Uh, well...","TWN":"呃，那個…"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"깜빡이를 켠다는 건, 나타나기 전에 미리 알려달라는 뜻이에요.","JPN":"ウィンカーを出すっていうのは、現れる前に予告してくれという意味です。","ENG":"Turning on the blinker means giving a heads-up before showing up.","TWN":"打方向燈是指先示警，。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"말도 없이 갑자기 나타나면 깜짝 놀랄 수도 있으니까.","JPN":"無言でいきなり現れるとびっくりするかもしれませんから。","ENG":"If you just pop up out of nowhere, it can really startle people.","TWN":"別突然冒出來嚇人"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"아하, 그런 거였군요. 확실히 알겠습니다.","JPN":"なるほど、そういう意味でしたか。わかりました。","ENG":"Ah, so that's what it means. Understood.","TWN":"啊，原來如此。明白了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"그럼, 앞으로 깜빡이를 켜도록 하겠습니다. 깜빡.","JPN":"では、これからはウィンカーを出します。チッカチッカ。","ENG":"Very well. I will turn on the blinker. Blink.","TWN":"好吧，我會開方向燈。嘟嘟。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"어, 어어? 네? 네에, 부탁드릴게요.","JPN":"ええっ？　はあ、お願いします。","ENG":"U-uh? What? O-okay, thank you.","TWN":"呃？什麼？好，好啦，謝謝。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야, 꼬맹이. 뭘 멍청하게 일일이 장단 맞춰주고 있냐?","JPN":"おい、おこちゃま。何を一緒に遊んでるんだよ？","ENG":"Hey, kid. Why are you playing along with her?","TWN":"嘿，小鬼，你為什麼配合她？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"지금 우리는 저 녀석들한테 납치된 거라고. 그러니까…….","JPN":"私たち、あいつらに拉致されたんだぞ。だから……","ENG":"We're being held captive by them. We should be–","TWN":"我們被她們囚禁了。我們應該…"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"깜빡. 깜빡이를 켜겠습니다.","JPN":"チッカチッカ。ウィンカーを出します。","ENG":"Blink. I have turned on the blinker.","TWN":"嘟嘟。我開了方向燈。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"마스터의 마스터께서 오십니다. 부디 모습을 단정히 하시길.","JPN":"マスターのマスターがお見えになります。身なりをお整えください。","ENG":"Master's master is coming. Please compose yourselves.","TWN":"主人的主人要來了，請大家安靜。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"마스터의 마스터라고……?","JPN":"マスターのマスター……？","ENG":"Master's master...?","TWN":"主人的主人……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그럼, 그 할망구 위에 누가 있다는 거야?","JPN":"じゃあ、あのババァの上に誰かがいるってことなのか？","ENG":"Does that mean there's someone above that old hag?","TWN":"意思是那個瘋婆子上面還有老大？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"반갑네, 자네들이 카나리아 스쿼드인가?","JPN":"初めまして、君たちがカナリア・スクワッドかね？","ENG":"Nice to meet you. You must be the Canary Squad.","TWN":"幸會。你們應該是金絲雀小隊。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"그리고 평의회에 온 것을 환영하네. 나는 의장 시솝이라고 하네.","JPN":"そして評議会へようこそ。私は議長のシソップだ。","ENG":"And welcome to the Council. I am Chairman Sysop.","TWN":"歡迎加入評議會。我是議長錫索普。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"시솝? 뭐야, 이 꼬맹이는?","JPN":"シソップ？　なんだ、このチビッ子は。","ENG":"Sysop? Who the heck is this kid?","TWN":"錫索普？這矮冬瓜是誰？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그리고 평의회라고? 그럼, 설마 우리를 납치한 게 검은 평의회라는 뜻이야?","JPN":"それに評議会？　じゃあ、私たちを拉致したのは黒い評議会ってこと？","ENG":"And the Council? Are you saying the ones who kidnapped us are the Dark Council?","TWN":"評議會？你是說綁架我們的就是黑暗評議會？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"웃기지 마. 평의회 정도 되는 거물이 우리 같은 피라미를 왜 납치하겠어?","JPN":"笑わせるなよ。評議会ほどの大物がなんで私たちみたいな雑魚を拉致するんだ？","ENG":"Don't make me laugh. Why would a big shot organization like the Council bother kidnapping nobodies like us?","TWN":"別鬧了。評議會這種大組織幹嘛綁架我們這種無名小卒？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"후후, 납치라…….","JPN":"ふふ、拉致か……","ENG":"Haha. Kidnapping, you say...","TWN":"哈哈，綁架？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"아무래도 중간에 무슨 착오가 생겼던 모양이로군.","JPN":"どうやら途中で何か誤解があったようだな。","ENG":"It seems there was a misunderstanding somewhere along the way.","TWN":"看來這裡有誤會。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"과격한 방식이었다면 사과하지. 나는 어디까지나 자네들을 손님으로서 이곳에 초청했다네.","JPN":"やり方が過激だったのなら謝罪しよう。私はあくまでも君たちを客人としてここに招待したんだ。","ENG":"If things got rough, I apologize. I only intended to invite you as guests.","TWN":"如果起了衝突，我道歉。我只是想邀請你們做客而已。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"왜냐하면 자네들은 작고 미약한 존재지만, 동시에 이 세계를 바꿀 수도 있는 변수거든.","JPN":"なぜなら君たちは小さく弱い存在だが、同時にこの世界を変え得る変数だからだ。","ENG":"After all, though you may be small and insignificant, you also hold the variable to change the world.","TWN":"畢竟，你們雖小且無足輕重，但同時也是改變世界變量。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"손님 좋아하시네! 요즘은 환영 인사로 생사람 어깨를 뽑냐? 아직도 욱씬 거리거든?","JPN":"客人！？　最近は歓迎のあいさつで人の肩を外したりするのか？　まだずきずきするんだけど。","ENG":"Guests? Oh yeah? Since when do you greet guests by dislocating their shoulders? It still hurts, you know!","TWN":"客人？從什麼時候起招待客人會扭斷肩膀？我還在痛呢！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"잠깐만요! 세계를 바꿀 변수라고요?","JPN":"待ってください！　世界を変え得る変数ですって？","ENG":"Wait a second! The variable to change the world?","TWN":"等一下！改變世界的變量？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그렇다면, 저번처럼 이 세계에 무슨 위험한 일이 또 발생할지도 모른다는 건가요?","JPN":"それって、この前のようにこの世界に何か危険なことがまた発生するかもしれないということですか？","ENG":"Does that mean something dangerous is going to happen in this world again, like last time?","TWN":"那是不是又要在這世界發生什麼危險事件，像上次一樣？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"그렇다네, 루이즈 양.","JPN":"そのとおりだ、ルイーズ君。","ENG":"Indeed, Louisé.","TWN":"沒錯，露易絲。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"클리포트 게임이 끝나고, 이 세계는 한 차례 변화를 겪었지.","JPN":"クリフォトゲームが終わり、この世界は一度変化を経験した。","ENG":"After the Qliphoth Game ended, this world underwent a major shift.","TWN":"逆卡巴拉遊戲結束後，這世界經歷了重大轉變。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"그리고 그 변화로 인해서, 달의 뒷면에 있던 고철 더미가 이 땅에 내려왔다네.","JPN":"そしてその変化により、月の裏側にいた鉄くずがこの地に降りた。","ENG":"And as a result, Scraps, who had been on the dark side of the moon, has descended to this land.","TWN":"結果是，曾在月球背面的廢鐵降臨此地。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"달의 뒷면에 있던 고철 더미……?","JPN":"月の裏側にいた鉄くず……？","ENG":"Scraps, who had been on the dark side of the moon...?","TWN":"曾在月球背面……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L28_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야! 너, 지금…! 그거 마더 쉽을 말하는 거야……?","JPN":"おい！　あんた、今の……！　それ、マザーシップのことか……？","ENG":"Wait! What you just said...! Are you talking about the mothership...?","TWN":"等等！你剛剛說的……指母艦？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"네가 마더 쉽에 대해서 알고 있다고……?","JPN":"あんた、マザーシップを……知ってるのか……？","ENG":"You know about the mothership...?","TWN":"你知道母艦？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"물론이네, 쿠드랴프카.","JPN":"もちろんだ、クドリャフカ。","ENG":"Of course, Kudryavka.","TWN":"當然了，庫德里亞夫卡。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"그것은 인류사의 분기점마다 출몰하여, 인류를 시험하는 존재. 클리포트의 마왕이라네.","JPN":"それは人類史の分岐点ごとに現れ、人類を試す存在。クリフォトの魔王だ。","ENG":"It's an entity that appears at critical junctures in human history to test humanity. A Demon Lord of Qliphoth.","TWN":"他在人類歷史的關鍵時刻出現，考驗人類，是逆卡巴拉魔王。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"그리고 동시에 우리의 모체 되는 존재이기도 하지.","JPN":"そして同時に私たちの母体に当たる存在でもある。","ENG":"And at the same time, it's also our source body.","TWN":"同時，他也是我們的源體。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"클리포트의 마왕이라고요……?","JPN":"クリフォトの魔王……？","ENG":"Demon Lord of Qliphoth...?","TWN":"逆卡巴拉魔王……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그럼, 관리국 최고등급 재난경보 같은 사태가 다시 발생할 수도 있다는 뜻인가요?","JPN":"じゃあ、管理局最高ランクの災難警報みたいな事態がまた起こる可能性があるということですか？","ENG":"So, does that mean we're going to face a situation as bad as the Administration's highest-level disaster alert?","TWN":"意思是我們要面臨管理局最高級別災難警報的局面？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"훌륭해. 이해가 빨라서 좋군.","JPN":"見事だ。理解が早くて助かるな。","ENG":"Precisely. I'm glad you're quick to understand.","TWN":"沒錯，很高興你能理解。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"저 고철 더미를 저대로 방치해 두었다간, 틀림없이 끔찍한 재난을 일으키게 될 거야.","JPN":"あの鉄くずをあのまま放置すれば、きっと悲惨な災いが起こることになるだろう。","ENG":"If Scraps is left alone, it will undoubtedly cause a catastrophic disaster.","TWN":"若放任廢鐵不管，必將引發災難性浩劫。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"다행히 저것의 존재를 알고 있는 아버지께서도 안배를 해두시겠지만, 결과적으로는 한걸음이 부족하겠지.","JPN":"幸い、父はあれの存在をご存じで対策を講じるはずだが、結果的にはあと一歩が足りなくなる。","ENG":"Fortunately, my father, who is aware of its existence, will make some arrangements. But in the end, it won't be enough.","TWN":"幸運的是，我的父親知曉此事，會做些安排，但最終仍不足以解決。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"그 부족한 한걸음을 메우는 것이 자네들이 맡게 될 역할이라네.","JPN":"その足りない一歩を埋めるのが君たちの役割だ。","ENG":"And it will be your roles to fill in that one missing step.","TWN":"而你們的任務就是補足那最後一環。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"웃기지 마……!","JPN":"ふざけるな……！","ENG":"You've got to be kidding me...!","TWN":"你在開玩笑吧……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L47_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카?","JPN":"ライカ？","ENG":"Laika?","TWN":"萊卡？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"역할이라고? 누구 마음대로 그딴 걸 정해?","JPN":"役割だと？　勝手にそんなことを決めるな。","ENG":"Our roles? Who are you to decide that for us?","TWN":"我們的任務？你是誰，憑什麼決定我們的事？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"달의 뒷면을 관측하던 우리 탐사대는 마더 쉽이 통솔하던 함대들에게 전부 요격당했어!","JPN":"月の裏側を観測していた私たち探査隊は、マザーシップが率いてた艦隊にみんな迎撃された！","ENG":"When we were observing the dark side of the moon, our exploration team was completely wiped out by the mothership's fleet!","TWN":"當我們觀察月球背面時，探險隊全被母艦艦隊殲滅！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그 끝없이 펼쳐진 우주 지옥에서 내가 어떻게 빠져나온 줄 알기나 해?","JPN":"あの果てしない宇宙の地獄から私がどうやって逃げたか、知らないだろ！","ENG":"Do you have any idea how I managed to escape that hellish void of space?","TWN":"你知道我怎麼從那無盡的宇宙地獄中逃出來的嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"눈앞에서 동료들이 끔찍하게 터져 죽는 걸 미끼 삼아서 간신히 도망쳤다고……!","JPN":"目の前で仲間たちが無惨に弾けて死んでいくのを囮にして、やっとのことで逃げたんだ……！","ENG":"I barely survived by using my crewmates' bodies as bait while they were blown to pieces right in front of me...!","TWN":"用在眼前慘烈地爆炸身亡的同伴作為誘餌，才勉強逃脫的！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"알아? 아직도 동료들의 원망 섞인 목소리가 생생해!","JPN":"わかるか？　いまだに仲間たちの恨みの声が聞こえるんだ！","ENG":"You have any idea how loud their screams still echo in my head?!","TWN":"知道嗎？我至今仍能清晰地聽到同伴們怨恨的聲音！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"쿠드랴프카… 내 호출 부호를 부르짖는 그 비명이 말이야……!","JPN":"クドリャフカ……私のコードネームを叫ぶあの悲鳴が……！","ENG":"Kudryavka... The scream of their calling out my code name in agony...!","TWN":"庫德里亞夫卡……呼喚我代號的那尖叫聲！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"지, 진정해요, 라이카……!","JPN":"お、落ち着いて、ライカ……！","ENG":"L-Laika, calm down...!","TWN":"冷，冷靜點，萊卡！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"더 들을 것도 없어! 여기서 나가자, 꼬맹이!","JPN":"もういい！　ここから出よう、おこちゃま！","ENG":"There's nothing more to say! We're getting out of here, kid!","TWN":"沒什麼好說的了！我們快離開這裡，小鬼！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"마더 쉽과 엮여서는 안 돼…! 죽어. 정말로 죽는다고……!","JPN":"マザーシップと関わっちゃダメだ……！　死ぬ、本当に死ぬんだ……！","ENG":"We can't get involved with the mothership...! It's suicide. We're all going to die...!","TWN":"不能和母艦糾纏不清！會死，真的會死的！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하물며, 우리는 카운터도 뭣도 아니잖아……!","JPN":"それに私たち、カウンターでもなんでもないんだよ……！","ENG":"Plus, we're not Counters or anything...!","TWN":"況且，我們不是制裁者，我們什麼都不是！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"세상에 널린 게 카운터야. 왜 하필 우리가 그 역할이라는 걸 맡아야 하는데……?","JPN":"世の中にカウンターなんてごまんといるのに、なんで私たちがその役割を担当しなきゃいけない……？","ENG":"There are plenty of Counters out there. Why do we have to be the ones to play this role...?","TWN":"世界上到處都是制裁者。為什麼偏偏是我們要承擔這個角色？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"두 분 모두 자리에서 멈추세요.","JPN":"お二人とも、お待ちください。","ENG":"Both of you, stop right there.","TWN":"兩位都請留步。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L17_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"……비켜. 메이드.","JPN":"……どけ、メイド。","ENG":"...Move it, maid.","TWN":"……讓開！女僕。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"마스터의 마스터께서 아직 말씀을 마치지 않으셨습니다.","JPN":"マスターのマスターはまだお話し中です。","ENG":"Master's master has not finished speaking yet.","TWN":"主人還沒有說完。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"그러니 자리에서 멈춰 경청하세요.","JPN":"その場でお聞きください。","ENG":"Please remain in your seats and listen.","TWN":"所以請停下來傾聽。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하! 이렇게 나온다 이거지?","JPN":"は！　そう来たか。","ENG":"Ha! So that's how it's gonna be?","TWN":"哈！要這樣是吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"이 봐, 메이드. 너희 할망구가 가르쳐주지 않았어?","JPN":"おい、メイド。あんたらのババァが教えてくれなかったのか？","ENG":"Listen here, maid. Didn't your old hag teach you anything?","TWN":"喂，女僕。那個瘋婆子教過你嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L28_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"납치한 인질의 몸은 최대한 꼼꼼히 수색해서 무기가 될 만한 건 전부 빼앗으라고.","JPN":"拉致した人質の体はできるだけ隈なくチェックして、武器になるようなものは全部奪えって。","ENG":"When you kidnap hostages, you're supposed to search them thoroughly and confiscate anything that could be a weapon.","TWN":"要仔細搜查綁架的人質，奪走所有可能成為武器的東西。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"이렇게 인질이 되려, 인질을 잡는 경우가 발생할 수도 있으니까.","JPN":"こんな風に人質がむしろ人質を取ることがあるかもしれないからな。","ENG":"Otherwise, the hostage might just turn the tables and take a hostage of their own.","TWN":"這樣可能會發生反客為主的情況。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"마스터의 마스터…? 어째서……?","JPN":"マスターのマスター……？　どうして……？","ENG":"Master's master...? Why...?","TWN":"主人的主人……怎麼會……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"후후, 걱정할 것 없다네, 로즈.","JPN":"ふふ、心配することはない、ローズ。","ENG":"Haha. No need to worry, Rose.","TWN":"呵呵，不用擔心，玫瑰。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L36_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"그나저나 인질이 되어보는 건 또 처음이군. 새로운 경험이야.","JPN":"それより人質になるのは初めてだな。新しい経験だ。","ENG":"Well, this is a first. Being held hostage is quite the new experience.","TWN":"話說回來，還是第一次成為人質呢。也算是一次新的體驗了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래? 근데 이거 어쩌냐? 이게 처음이자 마지막이 될 수도 있겠는 걸?","JPN":"そう？　でも残念。これが最初で最後になるかもしれないよ？","ENG":"Oh? But you know what? This could also be your last.","TWN":"是嗎？但是怎麼辦呢？這可能是第一次，也是最後一次了吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"모쪼록 그러지 않길 바라야겠군.","JPN":"くれぐれもそうならないことを祈ろう。","ENG":"Let's hope not.","TWN":"希望你不要這樣做。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"하지만 쿠드랴프카, 과연 그 작은 칼로 나에게 상처를 입힐 수 있을까?","JPN":"だがクドリャフカ、果たしてそんな小さなナイフで私を傷つけられるかね？","ENG":"But Kudryavka, do you really think that tiny knife can hurt me?","TWN":"但是庫德里亞夫卡，究竟能否用那把小刀傷到我呢？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"글쎄? 내 생각에 이 정도 날붙이면 동맥 정도는 손쉽게 쓱싹할 수 있을 것 같거든?","JPN":"どうかな？　これだけのサイズなら動脈くらい割と簡単にいけると思うけどね。","ENG":"Guess we'll find out. From what I can tell, this blade should be more than enough to slice through an artery.","TWN":"嗯？我覺得用這種刀刃輕鬆劃破動脈應該沒問題吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L41_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어디 누나랑 사이 좋게 실험해 볼까, 꼬마 의장님?","JPN":"お姉さんと仲良く実験してみようか、チビ議長？","ENG":"How about we run a little test, little Chairman?","TWN":"要不要和姊姊一起好好實驗一下呢，議長弟弟？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L42_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"아니, 그럴 필요 없다네.","JPN":"いや、その必要はない。","ENG":"No need for that.","TWN":"不，不需要那樣做。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L46_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"무, 무슨 악력이……!?","JPN":"な、なんて握力っ……！？","ENG":"W-what kind of grip strength–?!","TWN":"什，什麼怪力？！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L47_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"꼬맹이 주제에 손가락으로 칼날을 구부린다고……!?","JPN":"チビのくせに指で刃を折り曲げた……！？","ENG":"How are you bending a knife with just your fingers...?!","TWN":"這個矮冬瓜竟然用手指就能把刀刃掰彎！？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"왜냐하면 나는 인간이 아니거든.","JPN":"私は人間ではないのでね。","ENG":"Because I am not human.","TWN":"因為我不是人類。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L50_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"이 소체에 동맥 같은 건 존재하지 않아. 자네들처럼 따뜻한 피가 흐르지 않는다는 뜻이지.","JPN":"この素体に動脈など存在しない。君たちのように暖かい血は流れていないというわけだ。","ENG":"This body has no arteries. There's no warm blood flowing through it like yours.","TWN":"這個軀體中不存在動脈。也就是說，不會像你們一樣有溫熱的血液流動。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"따라서 나에게 자네들의 주관적인 감정의 잣대를 들이대 봤자, 곤란할 뿐이라네.","JPN":"だから君たちの主観的な感情の基準を押しつけられても、困ってしまうんだ。","ENG":"So using your subjective standards of emotion against me is pointless.","TWN":"因此，即使你們用主觀的情感標準來衡量我，也只會讓事情變得困難。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"나는 진정으로 그런 걸 느낄 수 없으니까 말이지.","JPN":"私は本当の意味でそういったものを感じることはできないからね。","ENG":"I can't truly feel any of that.","TWN":"因為我真的無法感受到那種東西。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"젠장, 설마 로봇이었어……!?","JPN":"くそ、まさかロボットだったとは……！？","ENG":"Damn it, you're a robot...?!","TWN":"可惡，竟然是機器人！？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카! 괜찮아요?","JPN":"ライカ！　大丈夫？","ENG":"Laika! Are you okay?","TWN":"萊卡！你沒事吧？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"다시 논점으로 돌아가지. 자네들을 선택한 이유를 물었었나?","JPN":"論点に戻るとしよう。君たちをなぜ選んだかだったね？","ENG":"Now then, let's get back to the subject. You asked why I chose you two, correct?","TWN":"我們回到正題。問我為什麼選擇你們嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"내가 자네들을 선택한 이유는 세계가 변하면서, 자네들이 소중한 것을 잃어버렸기 때문이야.","JPN":"私が君たちを選んだ理由は世界が変化し、君たちが大切なものを失ったからだ。","ENG":"I chose you because, after the world changed, you lost something precious.","TWN":"我選擇你們的原因是因為隨著世界的變化，你們失去了珍貴的東西。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"인간은 잃어버린 것을 되찾으려 할 때, 때때로 놀라운 힘을 발휘하기 마련이거든.","JPN":"人間は失ったものを取り戻そうとする時に、凄まじい力を発揮することがある。","ENG":"When humans try to reclaim what they've lost, they often display surprising levels of strength.","TWN":"當人類試圖找回失去的東西時，往往會展現出驚人的力量。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"소중한 것이라고요……?","JPN":"大切なもの……？","ENG":"Something precious...?","TWN":"你說是珍貴的東西？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"INTERN_MAIN_NPC_SHADOW","text":{"KOREA":"좋아요! 도전하겠습니다!","JPN":"いいでしょう！　挑戦します！","ENG":"All right! Challenge accepted!","TWN":"好！挑戰！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_MILITIA_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_MAIN_NPC_SHADOW","text":{"KOREA":"펠리세트의 꿈을 이루는 데 저도 있는 힘껏 도와드릴게요!","JPN":"フェリセットの夢を叶えるのに、私も精一杯お手伝いします！","ENG":"I'll help Félicette achieve her dream!","TWN":"我也會盡力幫忙實現費莉塞特的夢想的！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_MILITIA_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"INTERN_MAIN_NPC_SHADOW","text":{"KOREA":"헥─! 헥─!","JPN":"ひー、ひー！","ENG":"*Huff–!* *Huff–!*","TWN":"呼—！呼—！"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"THEMA_MILITIA_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_MAIN_NPC_SHADOW","text":{"KOREA":"헤헤, 힘들 때도 있지만 동료들과 함께 경기에 나올 수 있어서 무척 즐거워요!","JPN":"へへ、大変なこともありますけど、仲間と一緒に試合に出られてすごく楽しいです！","ENG":"He he. It's tough sometimes but I really enjoy being able to play with my team!","TWN":"嘿嘿，雖然也有累的時候，但能和同伴們一起參加比賽，我覺得很開心！"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"THEMA_MILITIA_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"INTERN_MAIN_NPC_SHADOW","text":{"KOREA":"또 이렇게 많은 분들이 저희를 지켜보고 있다고 생각하면, 왠지 설레고 기쁜 걸요!","JPN":"そしてこんなにたくさんの方々に見てもらえているなんて、すごく嬉しくてワクワクします！","ENG":"Also, knowing that a lot of you are rooting for us kinda makes me all giddy and happy for some reason!","TWN":"而且一想到有這麼多人在注意我們，就覺很興奮，很高興！"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"THEMA_MILITIA_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_MAIN_NPC_SHADOW","text":{"KOREA":"그래서…….","JPN":"だから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"THEMA_MILITIA_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_MAIN_NPC_SHADOW","text":{"KOREA":"그래서 저 이번 리그에서 꼭 우승하고 싶어요!","JPN":"だから私は今回のリーグで絶対に優勝したいです！","ENG":"So that's why I want to win the Gauntlet!","TWN":"所以我很想在這次的聯賽中奪冠！"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"THEMA_MILITIA_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"INTERN_MAIN_NPC_SHADOW","text":{"KOREA":"우승해서 펠리세트의 꿈을 이루는 데 보탬이 되고 싶어요!","JPN":"優勝して、フェリセットの夢を叶えるために、役に立ちたいです！","ENG":"I want to become the champion and help Félicette achieve her dream!","TWN":"我想奪得冠軍，好幫助費莉塞特實現夢想！"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"THEMA_MILITIA_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"INTERN_MAIN_NPC_SHADOW","text":{"KOREA":"펠리세트랑 라이카, 두 사람은 저에게 가슴이 두근거리는 꿈이란 게 뭔지 알려주었으니까!","JPN":"フェリセットとライカ、この二人は私にワクワクする夢というものを教えてくれたんです！","ENG":"Because Félicette and Laika both showed me how exciting it is to have one!","TWN":"費莉塞特和萊卡，是她們二個讓我知道什麼是令人心動的夢想！"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"THEMA_MILITIA_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"INTERN_MAIN_NPC_SHADOW","text":{"KOREA":"눈 부시게 빛나는 꿈에 닿을 수 있도록…… 힘껏 도와드리고 싶어요!","JPN":"眩しく光る夢に届くように……精一杯役に立ちたいです！","ENG":"I'm going to help them with everything I've got...! So they can finally reach their dazzling dream!","TWN":"我想盡我所能幫助她們……讓她們實現耀眼的夢想！"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"THEMA_MILITIA_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……윽!","JPN":"……うっ！","ENG":"...Ngh!","TWN":"……呃！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"시끄러워, 개수작 부리지 마!","JPN":"うるさい！　勝手なこと言うんじゃねえよ！","ENG":"Shut it. Cut the crap!","TWN":"吵死了，別耍花招！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"너희만 아니었어도 지금쯤 소중한 상금과 함께 행복한 시간을 보내고 있었을 거라고!","JPN":"あんたたちが来なければ、今頃大切な賞金と一緒に幸せな時間を過ごしていたはずだったんだ！","ENG":"If it weren't for you, we'd be living it up right now, celebrating with that sweet prize money!","TWN":"要不是因為你們，我現在就能和珍貴的獎金一起度過快樂的時光了！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야, 꼬맹이! 너도 뭐라고 한 마디……","JPN":"おい、おこちゃま！　あんたもなんか……","ENG":"Hey, kid! You too, say someth–","TWN":"喂，小鬼！你也說點什麼…"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"으음?","JPN":"うん？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야, 펠리세트! 너 왜 그래?","JPN":"おい、フェリセット！　どうした？","ENG":"Félicette! What's wrong?","TWN":"喂，費莉塞特！怎麼了？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"네? 아니… 그게 문득 어떤 기억이 떠올라서…. 별 건 아니에요…….","JPN":"えっ？　ううん……それが、ふと何かを思い出して……大したことじゃないわ……","ENG":"Huh? Oh... it's nothing. Just a memory popped up out of nowhere... Really, it's nothing...","TWN":"嗯？不……只是突然想起了一些記憶……沒什麼特別的……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"별 게 아니라고? 그런데 왜 질질 짜고 있어?","JPN":"大したことじゃない？　じゃあなんで泣いてんだよ？","ENG":"Nothing, huh? Then why are you crying?","TWN":"沒什麼大不了的？那你為什麼哭得這麼厲害？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"무슨 소리예요? 제가 울고 있다고요?","JPN":"何を言ってるの？　私が泣いてる？","ENG":"Crying? Me? What are you talking about?","TWN":"什麼意思？你說我在哭嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"제가 무슨……","JPN":"私は泣いてなんか……","ENG":"I'm not–","TWN":"我怎麼會……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Huh?","TWN":"咦？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"진짜로… 울고 있잖아? 왜 눈물이 나는 거지……?","JPN":"本当に……泣いてる？　どうして涙が出るんだろう……？","ENG":"I'm... really crying. But why...?","TWN":"真的……在哭嗎？為什麼會流淚呢？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"잠깐, 꼬맹이, 너……?","JPN":"待てよ、おこちゃま、あんた……？","ENG":"Hold on, kid, are you...?","TWN":"等等，小鬼，你？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"아마도 정보 말소의 후유증이겠지.","JPN":"おそらく情報抹消の後遺症だろう。","ENG":"It's likely the aftereffect of information erasure.","TWN":"可能是資訊抹消的後遺症吧。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"데자뷰는 가장 대표적인 정보 말소의 후유증이니까.","JPN":"デジャヴはもっとも代表的な情報抹消の後遺症だからな。","ENG":"Deja vu is one of the most common aftereffects of information erasure.","TWN":"既視感是資訊抹消最典型的後遺症。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"데자뷰? 정보 말소의 후유증이라고……?","JPN":"デジャヴ？　情報抹消の後遺症……？","ENG":"Deja vu...? Aftereffects of information erasure...?","TWN":"既視感？是資訊抹消的後遺症嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"갑작스럽게 세계가 바뀌고, 정보가 갱신된다 해도, 인간의 인식은 그 속도를 따라잡지 못하는 경우가 있거든.","JPN":"突然世界が変化して情報が更新されても、人間の認識はそのスピードに追い付けない場合がある。","ENG":"When the world suddenly changes and information is updated, the human mind can't always keep up.","TWN":"即使世界突然改變，資訊更新，人類的認知也可能跟不上這種速度。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"그래서 지워지지 않는 얼룩처럼 데자뷰가 일어나고, 기억에 혼선이 발생하지.","JPN":"だから、消えない染みのようにデジャヴが発生し、記憶が混乱する。","ENG":"So, like a stubborn stain that won't wash out, deja vu can occur, causing memory interference.","TWN":"所以就像無法抹去的污點一樣，產生了既視感，記憶出現了混亂。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"실은, 라이카…….","JPN":"実はね、ライカ……","ENG":"Actually, Laika...","TWN":"其實，萊卡……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이건 순전히 제 기분 탓일지도 모르겠지만…….","JPN":"これは、ただの気のせいかもしれないけど……","ENG":"I could be just mistaken, but...","TWN":"這有可能完全是我的錯覺……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그 우주선이 나타난 뒤로, 방금처럼 그런 기억이 떠오른 적이 몇 번이나 있었어요.","JPN":"あの宇宙船が現れてから、今みたいに、いつかの記憶が浮かび上がってきたことが何度もあったの。","ENG":"Ever since that spaceship appeared, I've been having those kinds of memories.","TWN":"自從那艘太空船出現後，像剛才那樣的記憶已經浮現過好幾次了。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"왠지 잊어서는 안 되는 걸, 잊어버린 것 같은 기분…….","JPN":"何か忘れちゃいけないことを、忘れてるような……","ENG":"It feels like I've forgotten something important that I wasn't supposed to forget...","TWN":"總覺得忘記了不該忘記的東西……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카는… 그런 적 없었어요……?","JPN":"ライカは……なかった……？","ENG":"Laika... Have you ever felt that way...?","TWN":"萊卡……沒有發生過那樣的事嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"인간의 이름. 인간의 기준. 그런 건 모른다.","JPN":"人間ノ名前。人間ノ基準。ソンナコトハ知ラナイ。","ENG":"Human name. Human standards. I don't know.","TWN":"人類的名字，人類的標準，這些我都不知道。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_MILITIA_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"덩치가 작은 여자. 나무로부터 내려온 존재…….","JPN":"小サイ女。木ヨリ送ラレタ存在……","ENG":"Small girl. Descended from the Tree...","TWN":"身材嬌小的女子。從樹上降臨的存在……"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_MILITIA_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"나 참, 침식체 주제에 아주 게을러 빠졌구만?","JPN":"ったく、侵食体のくせに怠けやがって。","ENG":"Unbelievable. For a C.O., you're pretty lazy, huh?","TWN":"哎呀，作為侵蝕體竟然這麼懶惰？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_MILITIA_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"이름도 모르면서 누가 누굴 찾는다는 거야, 이 멍청아!","JPN":"名前も知らずに人探しなんかできるもんか、バカ！","ENG":"You don't even know her name. How do you expect to find her, you idiot?","TWN":"連名字都不知道，誰找誰啊，你這個笨蛋！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_MILITIA_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"동포를 통해서. 정보를 전달받았다.","JPN":"仲間ガ、情報ヲクレタ。","ENG":"Through my kind. Received information.","TWN":"透過同胞，收到了資訊。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_MILITIA_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"너희 셋. 계속 함께였다. 그러니까 알 수 있다.","JPN":"オマエタチ3人。ズット一緒ダッタ。ダカラワカル。","ENG":"You three. Always together. So we know.","TWN":"你們三個，一直在一起，所以能知道。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_MILITIA_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"잠깐, 셋이라고?","JPN":"待て、3人だと？","ENG":"Wait, three?","TWN":"等等，三個……？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_MILITIA_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그러고 보니…….","JPN":"言われてみれば……","ENG":"Now that you mention it...","TWN":"這麼說來……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그때, 그 말하는 침식체는 분명 누군가를 찾고 있었어.","JPN":"あの時、あのしゃべる侵食体は確かに誰かを探していた。","ENG":"That talking C.O. was definitely looking for someone.","TWN":"那時，那說話的侵蝕體顯然在尋找某個人。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그 녀석은 우리 <color=#ffd34c>셋</color>이 항상 함께였다고 했지.","JPN":"あいつは私たち<color=#ffd34c>3人</color>がずっと一緒だったと言ってたっけ。","ENG":"He said the <color=#ffd34c>three</color> of us were always together.","TWN":"那傢伙說我們<color=#ffd34c>三人</color>總是在一起。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"셋이라고요?","JPN":"3人？","ENG":"Three?","TWN":"三個？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래, 셋.","JPN":"ああ、3人。","ENG":"Yeah, three.","TWN":"對，三個。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"처음에는 당연히 유미나 얘기인 줄 알았는데, 곰곰이 생각해 보니까 역시 아닌 것 같아.","JPN":"最初は当然ミナのことだろうと思ったけど、よく考えてみたらやっぱりなんか変。","ENG":"At first, I thought he was talking about Yoo Mina. But the more I think about it, that's not it.","TWN":"一開始我以為是在說劉米娜，但仔細想想，似乎不是這樣。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"분명히 우리 중에 누군가… 카나리아 스쿼드에 누군가가 한 명이 더 있었어…….","JPN":"きっと私たちの中に……カナリア・スクワッドに誰かもう1人いたんだ……","ENG":"There was definitely someone else among us... someone in Canary Squad...","TWN":"肯定是我們中的某個人……金絲雀小隊裡還有一個人……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"제 기억도 비슷해요.","JPN":"私の記憶もそれに近いわ。","ENG":"My memory is similar.","TWN":"我的記憶也差不多。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이름과 얼굴이 떠오르지는 않지만… 틀림없이 기억 속에 그 아이는 웃고 있었어요…….","JPN":"名前と顔は思い出せないけど……確かに記憶の中のその子は笑ってた……","ENG":"I can't remember her name or face, but... I remember her smiling...","TWN":"雖然名字和臉龐已經模糊不清……但在記憶中，那孩子一定是在微笑著……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그렇다면, 설마…….","JPN":"ってことは、まさか……","ENG":"If that's the case, then...","TWN":"難道……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"자네들이 잃어버린 것은 <color=#ffd34c>인연</color>…….","JPN":"君たちが失ったものは<color=#ffd34c>絆</color>……","ENG":"What you two lost was a <color=#ffd34c>bond</color>...","TWN":"你們失去的是<color=#ffd34c>緣分</color>……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"이 땅에 강림한 세피라의 힘이 사라지면서 자네들은 소중한 누군가를 잃게 되었어.","JPN":"この地に降臨したセフィラの力が消え、君たちは大切な誰かを失うことになった。","ENG":"When Sephira's power descended upon this land and then vanished, you lost someone precious.","TWN":"隨著降臨此地的生命樹之力消失，你們失去了某個珍貴的人。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"그리고 방금까지 그것을 잃었다는 사실조차 망각하고 있었지.","JPN":"そして今までそれを失ったことさえも忘れていた。","ENG":"And until just now, you didn't even realize that you had lost her.","TWN":"而且在此之前甚至忘記自己已經失去它的事實。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"하지만 사람과 사람 사이에 깊게 맺어진 인연은 그리 단순하게 지울 수 있는 게 아니야.","JPN":"だが、人と人の間に結ばれた深い絆はそう簡単に消せるものではない。","ENG":"But bonds deeply tied between people aren't so easily erased.","TWN":"但是人與人之間深厚的緣分並不是那麼簡單就能抹去的。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"그리고 때때로 인연이라는 건, 기적을 만들어내기도 하지.","JPN":"そして時に絆とは、奇跡を生み出すこともある。","ENG":"And sometimes, those bonds can even create miracles.","TWN":"有時候，緣分也會創造奇蹟。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"그러니까 내가 자네들에게 기회를 주겠네.","JPN":"だから、私が君たちにチャンスを与えよう。","ENG":"So, I'm giving you a chance.","TWN":"所以，我會給你們一次機會。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"자네들이 잃어버렸던 인연을 스스로의 힘으로 되찾고 기적에 다다를 기회를.","JPN":"失った絆を自らの力で取り戻し、奇跡にたどり着くチャンスを。","ENG":"A chance to reclaim the bond you lost and the opportunity to reach a miracle.","TWN":"你們憑藉自己的力量找回失去的羈絆，迎接奇蹟的機會。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};